struct CFFDeobfuscator : public FunctionPass {
    static char ID;
    CFFDeobfuscator() : FunctionPass(ID) {}

    bool runOnFunction(Function &F) override {
        // 查找可能的分发器基本块：包含大量switch或indirectbr
        for (auto &BB : F) {
