                if (auto *IBI = dyn_cast<IndirectBrInst>(&I)) {
                    errs() << "Found potential dispatcher in " << F.getName() << " at BB " << BB.getName() << "\n";
                    // 进一步分析...
                }
            }
        }
        return false;
    }
};
} // namespace

