def decrypt_string(enc_data, key):
    return bytes([b ^ key for b in enc_data])

# 从二进制中提取加密数据
with open('sample.exe', 'rb') as f:
    data = f.read()
# 假设加密数据在0x5000偏移处，长度20字节
enc = data[0x5000:0x5000+20]
key = 0xAB
print(decrypt_string(enc, key).decode('utf-8', errors='ignore'))


对于更复杂的混淆（如多轮异或、加减），需要逆向解密算法。建议使用IDA Pro的Hex-Rays反编译后，提取解密逻辑并翻译为Python。

OLLVM的虚假控制流通过插入不透明谓词（opaque predicate）创建永远为真或假的跳转，增加CFG复杂度。还原方法：识别不透明谓词并移除对应的死分支。常见模式：1）`xor eax, eax; jz target`（eax恒为0，跳转恒真）；2）`mov eax, 1; test eax, eax; jnz target`（恒真）。脚本思路：遍历所有基本块，检测条件跳转指令（jz/jnz/je/jne等），检查其条件是否恒成立。若条件寄存器来自常量赋值或异或自身，则标记为虚假分支，将跳转改为无条件跳转或NOP。IDAPython示例：

python
import idautils
import idc

def remove_bogus_cf():
    for func_ea in idautils.Functions():
        func_name = idc.get_func_name(func_ea)
        if 'sub_' in func_name:
            for head in idautils.Heads(func_ea, idc.get_func_attr(func_ea, FUNCATTR_END)):
                mnem = idc.print_insn_mnem(head)
                if mnem in ('jz', 'jnz', 'je', 'jne'):
                    # 检查前一条指令是否设置标志位
                    prev = idc.prev_head(head)
                    prev_mnem = idc.print_insn_mnem(prev)
                    if prev_mnem in ('xor', 'mov', 'test'):
                        # 获取操作数
                        if prev_mnem == 'xor' and idc.get_operand_value(prev, 0) == idc.get_operand_value(prev, 1):
                            # xor eax, eax -> 零标志位为1
                            if mnem in ('jz', 'je'):
                                # 恒真跳转，改为jmp
                                target = idc.get_operand_value(head, 0)
                                idc.patch_byte(head, 0xEB)  # jmp short
                                idc.patch_byte(head+1, (target - head - 2) & 0xFF)
                                print(f"Patched at 0x{head:x} to jmp 0x{target:x}")
                            else:
                                # 恒假，NOP掉
                                idc.patch_byte(head, 0x90)
                                idc.patch_byte(head+1, 0x90)
                                print(f"NOPed at 0x{head:x}")


注意：实际OLLVM可能使用更复杂的不透明谓词（如基于全局变量），需要动态分析辅助。
